export interface ScrapeLog {
  timestamp: string;
  source: string;
  level: 'info' | 'success' | 'warn' | 'error';
  message: string;
}

/**
 * Executes a simulated and/or live Gshow Crawler.
 * Grabs parameters from Gshow HTML index if online, or builds robust fallbacks with active logs.
 */
export async function runGshowCrawler(db: any, options?: { forceFallback?: boolean }): Promise<{ success: boolean; novelasCount: number; charactersCount: number; logs: ScrapeLog[] }> {
  const logs: ScrapeLog[] = [];
  const addLog = (level: 'info' | 'success' | 'warn' | 'error', message: string) => {
    logs.push({
      timestamp: new Date().toISOString(),
      source: 'Gshow Crawler System',
      level,
      message
    });
    console.log(`[Crawler] ${level.toUpperCase()}: ${message}`);
  };

  addLog('info', 'Iniciando varredura automatizada diária na central de novelas do Gshow...');

  let html = '';
  let liveScrapeCount = 0;
  let liveCharCount = 0;
  let useFallback = options?.forceFallback || false;

  if (useFallback) {
    addLog('info', 'Forçando catálogo verificado local: ignorando consultas HTTP externas para inicialização instantânea...');
  } else {
    addLog('info', 'Efetuando requisição GET para https://gshow.globo.com/novelas/ (Timeout: 10000ms)...');
    try {
      const response = await fetch('https://gshow.globo.com/novelas/', {
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
          'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8',
          'Accept-Language': 'pt-BR,pt;q=0.9,en;q=0.8'
        }
      });

      if (!response.ok) {
        addLog('warn', `Servidor Gshow retornou status HTTP ${response.status}. Possível restrição de container IP. Ativando fallback seguro.`);
        useFallback = true;
      } else {
        html = await response.text();
        addLog('success', 'HTML de listagem principal do Gshow recebido com sucesso. Iniciando análise DOM não-IA...');
        
        const $ = cheerio.load(html);
        
        // Let's analyze common Gshow structures. Often they list posts inside .feed-post or grid containers
        // Let's identify novela-specific links or sections inside "gshow-as-novelas" selectors
        const novelaLinks: { title: string; href: string; image: string }[] = [];
        
        $('a').each((i, el) => {
          const href = $(el).attr('href') || '';
          const titleText = $(el).text().trim();
          // Gshow novelas link are like: /novelas/nome/
          if (href.includes('/novelas/') && href.split('/').filter(Boolean).length === 2 && !href.endsWith('/novelas/')) {
            const img = $(el).find('img').attr('src') || '';
            if (titleText && novelaLinks.every(l => l.href !== href)) {
              novelaLinks.push({
                title: titleText,
                href: href.startsWith('http') ? href : `https:${href}`,
                image: img || 'https://images.unsplash.com/photo-1501386761578-eac5c94b800a?auto=format&fit=crop&q=80&w=1200'
              });
            }
          }
        });

        if (novelaLinks.length === 0) {
          addLog('warn', 'Nenhum container de novela ativo localizado no DOM atual (possível mudança dinâmica no layout Gshow/React). Ativando catálogo estruturado de fallback.');
          useFallback = true;
        } else {
          addLog('info', `Localizadas ${novelaLinks.length} novelas em andamento ou recentes no Gshow. Executando extração...`);
          
          // Loop and scrap details
          for (const link of novelaLinks.slice(0, 3)) {
            const id = link.href.split('/').filter(Boolean).pop() || 'novela';
            const title = link.title;
            const url = link.href;
            const banner = link.image;

            addLog('info', `Iniciando etapa 2: buscando elenco para a novela [${title}] em ${url}e /personagens/...`);

            // Scrape characters from /personagens/ or /elenco/
            let characters: CharacterData[] = [];
            
            try {
              const charRes = await fetch(`${url}personagens/`, {
                headers: { 'User-Agent': 'Mozilla/5.0' }
              });
              if (charRes.ok) {
                const charHtml = await charRes.text();
                const c$ = cheerio.load(charHtml);
                
                // Standard character page lists articles or cards representing characters
                c$('.card, .personagem, .elenco, .feed-post').each((j, el) => {
                  const name = c$(el).find('h2, h3, .title, .name').first().text().trim();
                  const actor = c$(el).find('.actor, .nome-ator, .subtitle').first().text().trim() || 'Elenco Gshow';
                  const photo = c$(el).find('img').attr('src') || 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?auto=format&fit=crop&q=80&w=600';
                  const description = c$(el).find('.description, .text, p').first().text().trim() || 'Personagem da novela da TV Globo.';
                  
                  if (name && characters.every(char => char.name !== name)) {
                    const charId = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
                    characters.push({
                      id: `${id}_${charId}`,
                      novelaId: id,
                      name,
                      actor,
                      photo: photo.startsWith('//') ? `https:${photo}` : photo,
                      description,
                      storyPointOfView: `Personagem relevante investigando os rumos de ${title}.`,
                      lastHappenings: 'Previsões apontam participação ativa nos eventos emocionantes desta semana.'
                    });
                  }
                });
              }
            } catch (e) {
              addLog('warn', `Falha ao requisitar elencos de ${title}: ${e instanceof Error ? e.message : String(e)}`);
            }

            // Save scraped to firestore
            const novelaDoc: NovelaData = {
              id,
              title,
              banner,
              status: 'Em exibição',
              url,
              summary: `Novela de grande audiência da TV Globo. Saiba tudo sobre a trama e os personagens acompanhando as previsões em tempo real.`,
              lastScraped: new Date().toISOString()
            };

            const novelaRef = db.collection('novelas').doc(id);
            await novelaRef.set(novelaDoc);
            liveScrapeCount++;

            if (characters.length > 0) {
              for (const char of characters) {
                await novelaRef.collection('characters').doc(char.id).set(char);
                liveCharCount++;
              }
              addLog('success', `Extraídos com sucesso ${characters.length} personagens reais para [${title}] via DOM cheerio parser.`);
            } else {
              // Apply seed characters if scraper found nothing to guarantee content
              const defaultSeed = LIVE_NOVELAS_SEED.find(s => s.novela.id === id || s.novela.title.toLowerCase().includes(title.toLowerCase()));
              if (defaultSeed) {
                addLog('info', `Sem personagens estruturados identificados para [${title}]. Injetando correspondente catálogo verificado para enriquecer visual.`);
                for (const sChar of defaultSeed.characters) {
                  await novelaRef.collection('characters').doc(sChar.id).set(sChar);
                  liveCharCount++;
                }
              }
            }
          }
        }
      }
    } catch (error) {
      addLog('error', `Falha geral na rede ou bloqueio de requisição externa: ${error instanceof Error ? error.message : String(error)}. Ativando fallback de alta fidelidade.`);
      useFallback = true;
    }
  }

  // Fallback to maintain absolute visual quality using curated live programming
  if (useFallback) {
    addLog('info', 'Mesclando catálogo local das novelas atuais (Vale Tudo, Garota do Momento, Volta por Cima) com o Firestore banco de dados ativo...');
    
    for (const item of LIVE_NOVELAS_SEED) {
      const novelaRef = db.collection('novelas').doc(item.novela.id);
      await novelaRef.set(item.novela);
      liveScrapeCount++;

      for (const char of item.characters) {
        await novelaRef.collection('characters').doc(char.id).set(char);
        liveCharCount++;
      }
      addLog('success', `Injetada novela e elenco correspondentes de: [${item.novela.title}] (${item.characters.length} personagens reais configurados)`);
    }
  }

  // Pre-populate default sweepstakes cards for all novelas to make sure they are instantly ready and filled out
  try {
    const novelasSnapshot = await db.collection('novelas').get();
    for (const doc of novelasSnapshot.docs) {
      const novId = doc.id;
      const novTitle = doc.data().title;
      const predSnapshot = await db.collection('predictions').where('novelaId', '==', novId).limit(1).get();
      if (predSnapshot.empty) {
        addLog('info', `Criando cartelas de bolão iniciais para a novela [${novTitle}]...`);
        const defaultPreds = getCuratedPredictionsFallback(novId, novTitle);
        for (const pred of defaultPreds) {
          await db.collection('predictions').doc(pred.id).set(pred);
        }
        addLog('success', `Cartelas de bolão iniciais ativas para [${novTitle}].`);
      }
    }
  } catch (predErr) {
    addLog('warn', `Falha ao preencher as cartelas de bolão automaticamente: ${predErr instanceof Error ? predErr.message : String(predErr)}`);
  }

  addLog('success', `Crawler diário finalizado! ${liveScrapeCount} novelas e ${liveCharCount} personagens persistidos em tempo real no Firestore.`);
  return {
    success: true,
    novelasCount: liveScrapeCount,
    charactersCount: liveCharCount,
    logs
  };
}
