/**
 * Generates different episodic predictions based on factual plot events for a specific upcoming episode.
 * Checks the database FIRST to avoid repeated API requests (satisfies cached/saved constraint "para que não fique sempre gerando").
 */
export async function generateEpisodicPredictions(
  novelaId: string,
  novelaTitle: string,
  episode: string,
  factsList: string[],
  characters: any[],
  db: any
): Promise<EpisodicPredictionData[]> {
  // 1. Check if predictions already exist for this combination of novelaId and episode in Firestore
  try {
    const existingSnap = await db.collection("episodic_predictions")
      .where("novelaId", "==", novelaId)
      .where("episode", "==", episode)
      .get();
    
    if (!existingSnap.empty) {
      console.log(`[Gemini Episode Cache] Found ${existingSnap.size} saved predictions in Firestore for episode [${episode}] of [${novelaId}]. Returning cached values.`);
      return existingSnap.docs.map(d => d.data() as EpisodicPredictionData);
    }
  } catch (err) {
    console.error("[Gemini Episode Cache] Failed to lookup cache in Firestore:", err);
  }

  // 2. Not found in database -> we must generate them!
  const ai = getGeminiClient();

  if (!ai) {
    console.log(`[Gemini Episode] Curating simulation predictions for episode [${episode}] under [${novelaTitle}]...`);
    const fallbackPredictions = getCuratedEpisodicFallback(novelaId, novelaTitle, episode, factsList);
    
    // Save to Firestore for persistent caching
    for (const pred of fallbackPredictions) {
      await db.collection("episodic_predictions").doc(pred.id).set(pred);
    }
    return fallbackPredictions;
  }

  try {
    console.log(`[Gemini Episode] Generating content using gemini-3.5-flash for ${novelaTitle} / ${episode}. Basing on ${factsList.length} recent plot facts...`);
    
    const formattedFacts = factsList.length > 0 
      ? factsList.map((f, idx) => `- Fato ${idx + 1}: ${f}`).join("\n")
      : "- Nenhum fato reportado recentemente. Analise os rumos gerais da novela na mídia.";

    const formattedCharacters = characters && characters.length > 0
      ? characters.map(c => `- ${c.name} (${c.actor}): ${c.description || ""}`).join("\n")
      : "Teorias gerais com o elenco central.";

    const prompt = `Você é um crítico de novelas da Central Globo de Produções e especialista em análise de roteiro.
Dada a novela "${novelaTitle}", escreva 3 previsões ou bolões de voto DIFERENTES, POLÊMICOS E INSTIGANTES direcionados especificamente para o PRÓXIMO EPISÓDIO/CAPÍTULO (${episode}).

Essas previsões devem ser inteiramente baseadas nos fatos recentemente ocorridos na trama citados abaixo:
${formattedFacts}

E na ficha de personagens da novela:
${formattedCharacters}

Traga dilemas ricos no estilo telenovela (ex: revelação de segredo, confronto, traição, flagrantes, arrependimento, etc.).
Para cada dilema ou previsão do próximo episódio, determine:
1. Um título criativo e instigante em formato de pergunta (ex: "Será que X confrontará Y no hospital?").
2. Uma descrição detalhada do cenário que conecta os fatos acima informados com a eminência do ocorrido neste episódio específico (${episode}).
3. 3 ou 4 opções plausíveis e tensas para votação do público noveleiro.
4. Uma análise da inteligência artificial ponderando as vertentes com sensibilidade dramática.
5. Grau de confiança da IA na principal opção favorita (porcentagem de 0 a 100).
6. Opção que é a tendência lógica dramática principal do desfecho.

Forneça a saída rigorosamente estruturada como um JSON ARRAY em conformidade com o formato requisitado.`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          description: "Diferentes dilemas e previsões para o mesmo próximo capitulo",
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING, description: "A frase ou dilema polêmico para o próximo capítulo do bolão" },
              description: { type: Type.STRING, description: "Introdução contextual baseada nos fatos informados da trama e no próximo episódio" },
              options: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
                description: "3 a 4 opções de caminhos plausíveis para o bolão"
              },
              aiAnalysis: { type: Type.STRING, description: "Estudo crítico da IA ponderando os rumos do autor" },
              aiConfidence: { type: Type.INTEGER, description: "Taxa de probabilidade ou segurança da IA na opção favorita (1 a 100)" },
              mainTrend: { type: Type.STRING, description: "Opção que é a tendência lógica óbvia ou favorita nos bastidores" }
            },
            required: ["title", "description", "options", "aiAnalysis", "aiConfidence", "mainTrend"]
          }
        }
      }
    });

    const text = response.text || "[]";
    const dataList = JSON.parse(text);

    const result: EpisodicPredictionData[] = [];
    for (let i = 0; i < dataList.length; i++) {
      const p = dataList[i];
      const predId = `episodic_${novelaId}_${episode.toLowerCase().replace(/[^a-z0-9]+/g, "-")}_${i + 1}`;
      
      const votes: { [option: string]: number } = {};
      p.options.forEach((opt: string) => {
        votes[opt] = Math.floor(Math.random() * 30) + 3; // Seed initial balanced community votes
      });

      const element: EpisodicPredictionData = {
        id: predId,
        novelaId,
        episode,
        title: p.title,
        description: p.description,
        options: p.options,
        votes,
        aiAnalysis: p.aiAnalysis,
        aiConfidence: p.aiConfidence || 70,
        mainTrend: p.mainTrend,
        createdAt: new Date().toISOString(),
        factsUsed: factsList
      };

      // Save to Firestore
      await db.collection("episodic_predictions").doc(predId).set(element);
      result.push(element);
    }

    console.log(`[Gemini Episode] Successfully generated and stored ${result.length} episodic predictions!`);
    return result;

  } catch (err) {
    console.error("[Gemini Episode] Generation failed, using curated simulated episodic logic instead:", err);
    const fallback = getCuratedEpisodicFallback(novelaId, novelaTitle, episode, factsList);
    for (const pred of fallback) {
      await db.collection("episodic_predictions").doc(pred.id).set(pred);
    }
    return fallback;
  }
}

