import { NovelaData, CharacterData } from "./scraper.ts";
import { localDb } from "./localDb.ts";

/**
 * Normalizes title for best TMDB query results
 */
function cleanTitleForQuery(title: string): string {
  let clean = title.replace(/\([^)]*\)/g, "").trim();
  clean = clean.replace(/\s+/g, " ").trim();
  return clean;
}

interface TMDBTvResult {
  id: number;
  name: string;
  backdrop_path: string | null;
  poster_path: string | null;
}

interface TMDBCastMember {
  name: string;
  character: string;
  profile_path: string | null;
}

/**
 * Service to search and enrich Globo Novelas with actual TMDB banners and cast photos
 */
export async function enrichWithTMDB(
  novelas: { novela: NovelaData; characters: CharacterData[] }[] | any[]
): Promise<{ enrichedCount: number; logs: string[] }> {
  const logs: string[] = [];
  const statusLog = (msg: string) => {
    console.log(`[TMDB Service] ${msg}`);
    logs.push(msg);
  };

  const apiKey = process.env.TMDB_API_KEY;
  if (!apiKey || apiKey === "MY_TMDB_API_KEY" || apiKey.trim() === "") {
    statusLog("Avisos: TMDB_API_KEY não configurada no painel de segredos (.env / secrets). Enriquecimento pulado.");
    return { enrichedCount: 0, logs };
  }

  statusLog("Iniciando enriquecimento de catálogo via API do TMDB...");
  let enrichedCount = 0;

  for (const item of novelas) {
    const novelaId = item.novela?.id || item.id;
    const currentTitle = item.novela?.title || item.title;
    const charactersList: CharacterData[] = item.characters || [];

    if (!currentTitle) continue;

    const query = cleanTitleForQuery(currentTitle);
    statusLog(`Procurando novela: "${query}" (Título original: "${currentTitle}")`);

    try {
      // 1. Search for the TV Show in TMDB
      const searchUrl = `https://api.themoviedb.org/3/search/tv?api_key=${apiKey}&query=${encodeURIComponent(query)}&language=pt-BR`;
      const searchRes = await fetch(searchUrl);
      if (!searchRes.ok) {
        statusLog(`Erro na busca TMDB para "${query}": Status ${searchRes.status}`);
        continue;
      }

      const searchData = (await searchRes.json()) as { results: TMDBTvResult[] };
      const results = searchData.results || [];

      if (results.length === 0) {
        statusLog(`Nenhum resultado encontrado no TMDB para a novela "${query}".`);
        continue;
      }

      // Select the best matching result (usually first)
      const bestMatch = results[0];
      statusLog(`Correspondência encontrada: "${bestMatch.name}" (TMDB ID: ${bestMatch.id})`);

      // Update Novela attributes if found
      if (item.novela) {
        if (bestMatch.backdrop_path) {
          item.novela.banner = `https://image.tmdb.org/t/p/w1280${bestMatch.backdrop_path}`;
        } else if (bestMatch.poster_path) {
          item.novela.banner = `https://image.tmdb.org/t/p/w780${bestMatch.poster_path}`;
        }
      } else {
        if (bestMatch.backdrop_path) {
          item.banner = `https://image.tmdb.org/t/p/w1280${bestMatch.backdrop_path}`;
        } else if (bestMatch.poster_path) {
          item.banner = `https://image.tmdb.org/t/p/w780${bestMatch.poster_path}`;
        }
      }

      // 2. Fetch credits (actors and profiles) for this show
      const creditsUrl = `https://api.themoviedb.org/3/tv/${bestMatch.id}/credits?api_key=${apiKey}&language=pt-BR`;
      const creditsRes = await fetch(creditsUrl);
      if (creditsRes.ok) {
        const creditsData = (await creditsRes.json()) as { cast: TMDBCastMember[] };
        const cast = creditsData.cast || [];
        statusLog(`Carregados ${cast.length} elenco(s) do TMDB para "${bestMatch.name}".`);

        let matchedActors = 0;
        // Search cast list for our characters
        for (const char of charactersList) {
          // Attempt 1: Match actor name exactly or fuzzy (contained)
          let match = cast.find(
            (c) =>
              c.name.toLowerCase() === char.actor.toLowerCase() ||
              char.actor.toLowerCase().includes(c.name.toLowerCase()) ||
              c.name.toLowerCase().includes(char.actor.toLowerCase())
          );

          // Attempt 2: If not found, match character name
          if (!match) {
            match = cast.find(
              (c) =>
                c.character.toLowerCase().includes(char.name.toLowerCase()) ||
                char.name.toLowerCase().includes(c.character.toLowerCase())
            );
          }

          if (match && match.profile_path) {
            char.photo = `https://image.tmdb.org/t/p/h632${match.profile_path}`;
            matchedActors++;
          }
        }
        statusLog(`Enriquecidos ${matchedActors}/${charactersList.length} atores com fotos reais TMDB!`);
      }

      enrichedCount++;
    } catch (err: any) {
      statusLog(`Exceção durante busca TMDB para "${currentTitle}": ${err?.message || String(err)}`);
    }
  }

  statusLog(`Finalizado. Enriquecidas ${enrichedCount} novelas.`);
  return { enrichedCount, logs };
}

/**
 * High-level database orchestrator to fetch all novelas from active DB and enrich them via TMDB
 */
export async function enrichDatabaseWithTMDB(
  db: any,
  useLocalFallback: boolean
): Promise<{ success: boolean; enrichedCount: number; logs: string[] }> {
  const logs: string[] = [];
  const statusLog = (msg: string) => {
    console.log(`[TMDB Database Enricher] ${msg}`);
    logs.push(msg);
  };

  const apiKey = process.env.TMDB_API_KEY;
  if (!apiKey || apiKey === "MY_TMDB_API_KEY" || apiKey.trim() === "") {
    statusLog("TMDB_API_KEY não configurada nos Segredos do app. Enriquecimento ignorado.");
    return { success: false, enrichedCount: 0, logs };
  }

  try {
    if (useLocalFallback) {
      statusLog("Executando enriquecimento no Banco de Dados Local (localDb/db.json)...");
      const novelas = localDb.getNovelas();
      const { enrichedCount, logs: tmdbLogs } = await enrichWithTMDB(novelas);
      logs.push(...tmdbLogs);
      localDb.forceSave();
      statusLog("Banco de Dados Local persistido com sucesso!");
      return { success: true, enrichedCount, logs };
    } else {
      statusLog("Executando enriquecimento no Banco de Dados de Produção (Firestore)...");
      const novelasSnapshot = await db.collection("novelas").get();
      const novelasToEnrich: any[] = [];

      for (const doc of novelasSnapshot.docs) {
        const data = doc.data();
        const charsSnapshot = await doc.ref.collection("characters").get();
        const characters = charsSnapshot.docs.map(c => c.data());
        
        novelasToEnrich.push({
          id: doc.id,
          title: data.title,
          banner: data.banner,
          characters
        });
      }

      const { enrichedCount, logs: tmdbLogs } = await enrichWithTMDB(novelasToEnrich);
      logs.push(...tmdbLogs);

      // Write updates back to Firestore
      for (const item of novelasToEnrich) {
        statusLog(`Atualizando novela [${item.title}] no Firestore...`);
        // Update main novela document
        await db.collection("novelas").doc(item.id).update({
          banner: item.banner,
          lastScraped: new Date().toISOString()
        });

        // Update characters' documents
        for (const char of item.characters) {
          await db.collection("novelas").doc(item.id).collection("characters").doc(char.id).update({
            photo: char.photo
          });
        }
      }

      statusLog(`Banco de Dados Firestore atualizado com sucesso para ${enrichedCount} novelas!`);
      return { success: true, enrichedCount, logs };
    }
  } catch (error: any) {
    statusLog(`Erro grave durante enriquecimento database TMDB: ${error?.message || String(error)}`);
    return { success: false, enrichedCount: 0, logs };
  }
}
