import fs from "fs";
import path from "path";
import { LIVE_NOVELAS_SEED, NovelaData, CharacterData } from "./scraper.ts";
import { getCuratedPredictionsFallback } from "./gemini.ts";

export interface NovelDataExtended extends NovelaData {
  characters: CharacterData[];
  facts: string[];
}

export interface Prediction {
  id: string;
  novelaId: string;
  title: string;
  description: string;
  options: string[];
  votes: { [key: string]: number };
  mainTrend: string;
  createdAt: string;
  aiAnalysis?: string;
  aiConfidence?: number;
}

export interface EpisodicPrediction {
  id: string;
  novelaId: string;
  episode: string;
  title: string;
  description: string;
  options: string[];
  votes: { [key: string]: number };
  aiAnalysis?: string;
  mainTrend?: string;
}

export interface UserProfile {
  uid: string;
  displayName: string;
  email: string;
  photoURL: string;
  points: number;
  createdAt: string;
}

interface DbSchema {
  novelas: NovelDataExtended[];
  predictions: Prediction[];
  episodicPredictions: EpisodicPrediction[];
  users: UserProfile[];
  votes: { [key: string]: { option: string; selectedAt: string } }; // key: userId_predictionId
}

const DB_FILE_PATH = path.join(process.cwd(), "db.json");

class LocalDatabase {
  private data: DbSchema;

  constructor() {
    this.data = {
      novelas: [],
      predictions: [],
      episodicPredictions: [],
      users: [],
      votes: {}
    };
    this.load();
    if (this.data.novelas.length === 0) {
      this.bootstrapDefaults();
    }
  }

  private load() {
    try {
      if (fs.existsSync(DB_FILE_PATH)) {
        const fileContent = fs.readFileSync(DB_FILE_PATH, "utf-8");
        this.data = JSON.parse(fileContent);
        // Ensure standard fields exist if older version of db.json was present
        if (!this.data.novelas) this.data.novelas = [];
        if (!this.data.predictions) this.data.predictions = [];
        if (!this.data.episodicPredictions) this.data.episodicPredictions = [];
        if (!this.data.users) this.data.users = [];
        if (!this.data.votes) this.data.votes = {};
        console.log(`[LocalDatabase] Successfully loaded persistent local database from: ${DB_FILE_PATH}`);
      } else {
        console.log("[LocalDatabase] db.json file of persistent storage not found. A fresh one will be written.");
      }
    } catch (err) {
      console.error("[LocalDatabase] Error reading db.json. Fallback to empty memory state.", err);
    }
  }

  private save() {
    try {
      fs.writeFileSync(DB_FILE_PATH, JSON.stringify(this.data, null, 2), "utf-8");
    } catch (err) {
      console.error("[LocalDatabase] Error writing to db.json", err);
    }
  }

  private bootstrapDefaults() {
    console.log("[LocalDatabase] Bootstrapping curated Brazilian telenovelas seeds...");
    
    // Seed novelas and characters
    for (const seed of LIVE_NOVELAS_SEED) {
      this.data.novelas.push({
        ...seed.novela,
        characters: seed.characters,
        facts: this.getDefaultFactsForNovela(seed.novela.id)
      });

      // Seed core curated prediction cards
      const curated = getCuratedPredictionsFallback(seed.novela.id, seed.novela.title);
      for (const card of curated) {
        this.data.predictions.push({
          id: card.id,
          novelaId: card.novelaId,
          title: card.title,
          description: card.description,
          options: card.options,
          votes: card.votes || { "Sim": 0, "Não": 0 },
          mainTrend: card.mainTrend || "Indefinido",
          createdAt: card.createdAt || new Date().toISOString(),
          aiAnalysis: card.aiAnalysis,
          aiConfidence: card.aiConfidence
        });
      }
    }

    this.save();
    console.log("[LocalDatabase] Seeding finished successfully.");
  }

  private getDefaultFactsForNovela(novelaId: string): string[] {
    const defaultNovelaFacts: { [key: string]: string[] } = {
      "vale-tudo-remake": [
        "Maria de Fátima foi flagrada em flagrante em Angra dos Reis conspirando com César Ribeiro.",
        "Afonso Roitman suspeita profundamente das intenções de sua irmã Solange sobre a herança de família.",
        "Raquel recusou apoiar a expansão comercial de César por discordar veementemente de sua idoneidade."
      ],
      "garota-do-momento": [
        "Beatriz humilhou a rival no desfile da Perfumaria Carioca ao expor as mentiras sobre a fita de gravação.",
        "Clarice sentiu uma forte tontura ao recordar o timbre de voz de sua verdadeira filha Beatriz.",
        "Juliano ameaçou tirar todo o investimento da agência de publicidade caso os deslizes de sua filha continuem."
      ],
      "volta-por-cima": [
        "Madalena e Jão conseguiram a cópia digitalizada de liberação do montante do bilhete de loteria deixado por Lindomar.",
        "Tio Osmar comprou um apartamento cinematográfico no Leblon sob um codinome fantasma.",
        "Chico tentou atrapalhar o reencontro romântico de Madalena e Jão no terminal rodoviário da Viação Formosa."
      ]
    };
    return defaultNovelaFacts[novelaId] || [
      "Novos mistérios cercam a recepção fria entre os personagens principais.",
      "Uma aliança duvidosa sacudiu os bastidores da última semana.",
      "Conversas vazadas de bastidores geraram especulações sobre a próxima grande revelação."
    ];
  }

  // API Methods
  public forceSave(): void {
    this.save();
  }

  public getNovelas(): NovelDataExtended[] {
    return this.data.novelas;
  }

  public getPredictions(): Prediction[] {
    return this.data.predictions;
  }

  public getFacts(novelaId: string): string[] {
    const novela = this.data.novelas.find(n => n.id === novelaId);
    return novela ? novela.facts : this.getDefaultFactsForNovela(novelaId);
  }

  public addFact(novelaId: string, text: string): boolean {
    const novela = this.data.novelas.find(n => n.id === novelaId);
    if (novela) {
      if (!novela.facts) novela.facts = [];
      novela.facts.push(text);
      this.save();
      return true;
    }
    return false;
  }

  public saveNovelasFromCrawler(novelasWithChars: { novela: NovelaData; characters: CharacterData[] }[]) {
    for (const item of novelasWithChars) {
      const existing = this.data.novelas.find(n => n.id === item.novela.id);
      if (existing) {
        existing.title = item.novela.title;
        existing.banner = item.novela.banner;
        existing.summary = item.novela.summary;
        existing.lastScraped = item.novela.lastScraped;
        existing.characters = item.characters;
      } else {
        this.data.novelas.push({
          ...item.novela,
          characters: item.characters,
          facts: this.getDefaultFactsForNovela(item.novela.id)
        });
      }
    }
    this.save();
  }

  public savePredictionsFromGemini(novelaId: string, predictions: Prediction[]) {
    // Remove existing predictions for this novela to refresh with fresh ones
    this.data.predictions = this.data.predictions.filter(p => p.novelaId !== novelaId);
    this.data.predictions.push(...predictions);
    this.save();
  }

  public votePrediction(predictionId: string, option: string, userId: string, displayName?: string, photo?: string, email?: string): Prediction | null {
    const prediction = this.data.predictions.find(p => p.id === predictionId);
    if (!prediction) return null;

    const voteKey = `${userId}_${predictionId}`;
    const previousVote = this.data.votes[voteKey];

    if (!prediction.votes) prediction.votes = {};

    // Adjust counts
    if (previousVote) {
      const oldOpt = previousVote.option;
      if (prediction.votes[oldOpt] && prediction.votes[oldOpt] > 0) {
        prediction.votes[oldOpt]--;
      }
    }

    prediction.votes[option] = (prediction.votes[option] || 0) + 1;
    this.data.votes[voteKey] = { option, selectedAt: new Date().toISOString() };

    // Calculate leading option
    let leading = option;
    let maxCount = prediction.votes[option];
    for (const opt in prediction.votes) {
      if (prediction.votes[opt] > maxCount) {
        maxCount = prediction.votes[opt];
        leading = opt;
      }
    }
    prediction.mainTrend = leading;

    // Award user points
    this.awardPointsToUser(userId, 10, displayName, photo, email);

    this.save();
    return prediction;
  }

  public getEpisodicPredictions(novelaId: string, episode: string): EpisodicPrediction[] {
    return this.data.episodicPredictions.filter(p => p.novelaId === novelaId && p.episode === episode);
  }

  public saveEpisodicPredictions(preds: EpisodicPrediction[]) {
    for (const item of preds) {
      const idx = this.data.episodicPredictions.findIndex(p => p.id === item.id);
      if (idx !== -1) {
        this.data.episodicPredictions[idx] = item;
      } else {
        this.data.episodicPredictions.push(item);
      }
    }
    this.save();
  }

  public voteEpisodicPrediction(predictionId: string, option: string, userId: string, displayName?: string): EpisodicPrediction | null {
    const prediction = this.data.episodicPredictions.find(p => p.id === predictionId);
    if (!prediction) return null;

    const voteKey = `${userId}_${predictionId}`;
    const previousVote = this.data.votes[voteKey];

    if (!prediction.votes) prediction.votes = {};

    if (previousVote) {
      const oldOpt = previousVote.option;
      if (prediction.votes[oldOpt] && prediction.votes[oldOpt] > 0) {
        prediction.votes[oldOpt]--;
      }
    }

    prediction.votes[option] = (prediction.votes[option] || 0) + 1;
    this.data.votes[voteKey] = { option, selectedAt: new Date().toISOString() };

    let leading = option;
    let maxCount = prediction.votes[option];
    for (const opt in prediction.votes) {
      if (prediction.votes[opt] > maxCount) {
        maxCount = prediction.votes[opt];
        leading = opt;
      }
    }
    prediction.mainTrend = leading;

    this.awardPointsToUser(userId, 15, displayName);
    this.save();
    return prediction;
  }

  public broadcastEpisode(novelaId: string, episode: string): number {
    const beforeCount = this.data.episodicPredictions.length;
    // Remove matches
    const expiredPreds = this.data.episodicPredictions.filter(p => p.novelaId === novelaId && p.episode === episode);
    this.data.episodicPredictions = this.data.episodicPredictions.filter(p => !(p.novelaId === novelaId && p.episode === episode));

    // Clear related votes as well
    for (const pred of expiredPreds) {
      for (const k of Object.keys(this.data.votes)) {
        if (k.endsWith(`_${pred.id}`)) {
          delete this.data.votes[k];
        }
      }
    }

    this.save();
    return beforeCount - this.data.episodicPredictions.length;
  }

  private awardPointsToUser(userId: string, points: number, displayName?: string, photo?: string, email?: string) {
    let user = this.data.users.find(u => u.uid === userId);
    if (user) {
      user.points += points;
      if (displayName) user.displayName = displayName;
      if (photo) user.photoURL = photo;
    } else {
      this.data.users.push({
        uid: userId,
        displayName: displayName || "Fã de Novela",
        email: email || "",
        photoURL: photo || "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=200",
        points,
        createdAt: new Date().toISOString()
      });
    }
  }
}

export const localDb = new LocalDatabase();
